fn main(country_code: [u8; 2], allowed_countries: pub [[u8; 2]; 10], allowed_count: pub u32) {
    let mut found = false;
    for i in 0..10u32 {
        if i < allowed_count {
            if country_code == allowed_countries[i] { found = true; }
        }
    }
    assert(found, "country not in allowed list");
}

#[test]
